INSERT INTO t_p71821556_real_estate_catalog_.ai_memory (key, value, source) VALUES
('glossary_street_retail',   'Стрит-ритейл — торговые помещения на первых этажах жилых домов или отдельных зданий с выходом на пешеходный трафик улицы. Ключевой критерий — видимость и проходимость.', 'manual'),
('glossary_tc',              'ТЦ (торговый центр) / ТРЦ (торгово-развлекательный центр) — коммерческий объект, объединяющий множество арендаторов под одной крышей. Классифицируется по GLA: районный (<15 000 м²), окружной (15–40 000 м²), региональный (>40 000 м²).', 'manual'),
('glossary_bc',              'БЦ (бизнес-центр) — специализированное офисное здание. Классы: A (премиум, инженерия, управляющая компания), B+ и B (качественные), C (устаревший фонд). Класс напрямую влияет на ставку аренды и вакантность.', 'manual'),
('glossary_triple_net',      'Triple Net (NNN) — формат аренды, при котором арендатор оплачивает помимо базовой ставки все операционные расходы: налог на имущество, страховку, содержание здания. Снижает риски арендодателя.', 'manual'),
('glossary_wault',           'WAULT (Weighted Average Unexpired Lease Term) — средневзвешенный остаток срока аренды. Чем выше WAULT — тем стабильнее денежный поток объекта, тем ниже инвестиционный риск.', 'manual'),
('glossary_yield_compress',  'Yield Compression (сжатие доходности) — снижение cap rate при росте цен на недвижимость. Означает, что инвесторы готовы платить больше за тот же доход, — признак роста рынка.', 'manual'),
('glossary_noi',             'NOI (Net Operating Income) — чистый операционный доход объекта: выручка от аренды минус вакансия и операционные расходы (без учёта обслуживания долга и налога на прибыль). Базовый показатель инвестиционной оценки.', 'manual'),
('glossary_irr',             'IRR (Internal Rate of Return) — внутренняя норма доходности: ставка дисконтирования, при которой NPV проекта равен нулю. Для коммерческой недвижимости Краснодара хороший IRR — от 20% годовых.', 'manual'),
('glossary_npv',             'NPV (Net Present Value) — чистая приведённая стоимость: сумма дисконтированных денежных потоков за период владения минус цена покупки. Положительный NPV означает, что инвестиция прибыльнее альтернативы.', 'manual'),
('glossary_vacancy',         'Вакантность — доля пустующих площадей от общего предложения в сегменте или здании. Низкая вакантность (<5%) говорит о высоком спросе. Краснодар 2025: офисы ЦМР ~5%, склады ~3%.', 'manual'),
('glossary_opex',            'OPEX (Operating Expenses) — операционные расходы: коммунальные платежи, охрана, уборка, текущий ремонт, управление. Обычно 10–25% от арендного дохода в зависимости от типа объекта.', 'manual'),
('glossary_leaseback',       'Sale & Leaseback (продажа с обратной арендой) — схема, при которой собственник продаёт объект инвестору и одновременно становится арендатором на долгосрочный срок. Позволяет высвободить капитал, сохранив операционный контроль.', 'manual'),
('glossary_road_line',       'Линия улицы (1-я, 2-я, 3-я) — расположение объекта относительно проезжей части. 1-я линия — прямой выход на улицу с высоким трафиком (+20–30% к арендной ставке). 2-я — через двор или переулок. 3-я — глубоко во дворе.', 'manual'),
('glossary_anchor',          'Якорный арендатор (anchor tenant) — крупный арендатор, генерирующий поток посетителей для всего объекта (супермаркет, банк, аптека, фитнес-клуб). Наличие якоря снижает риск вакантности галереи.', 'manual'),
('glossary_psn',             'ПСН (помещение свободного назначения) — универсальное нежилое помещение без строгого функционального назначения. Может использоваться под офис, торговлю, салон, медицину. Самый ликвидный сегмент в Краснодаре.', 'manual'),
('glossary_discount_rate',   'Ставка дисконтирования — требуемая инвестором норма доходности для расчёта NPV и оценки будущих денежных потоков. В России привязана к ставке ЦБ + премия за риск. При ставке ЦБ 18% типичная ставка дисконтирования для недвижимости Краснодара — 22–26%.', 'manual')
INSERT INTO t_p71821556_real_estate_catalog_.ai_memory (key, value, source) VALUES
('faq_office_yield_cmr',     'Какая доходность офисов в ЦМР? По данным price_history 2026: офисы ЦМР — аренда 39 000 руб/м²/год, вакантность 5%. При покупке по 147 849 руб/м² cap rate ~21% до OPEX. Чистый cap rate с расходами — 17–19%.', 'manual'),
('faq_office_vs_psn',        'Что лучше — офис или ПСН? Для инвестора: ПСН универсальнее — принимает более широкий круг арендаторов (торговля, медицина, бьюти, еда). Офис — более предсказуем, но зависит от деловой активности района. ПСН на 1-й линии улицы даёт на 15–25% выше ставку аренды чем офис той же площади.', 'manual'),
('faq_warehouse_rent',       'Сколько стоит аренда склада в Краснодаре? По данным price_history 2026: склады (аренда) — средняя ставка 7 800–10 200 руб/м²/год (650–850 руб/м²/мес). Пашковский район — дешевле (~650 руб/м²/мес), ФМР — дороже (~850 руб/м²/мес). Вакантность складов ~3–5%.', 'manual'),
('faq_retail_caprate',       'Какой cap rate у торговой недвижимости Краснодара? Данные price_history 2026: торговые помещения (street retail) — cap rate 9–12%. ЦМР 1-я линия — 9–10%, спальные районы — 11–13%. Среднее по городу ~10–11%.', 'manual'),
('faq_gab_check',            'Как проверить ГАБ перед покупкой? Ключевые пункты: 1) проверить договор аренды (срок, ставка, индексация, условия расторжения); 2) проверить арендатора через ФНС и арбитраж; 3) оценить WAULT — должен быть >3 лет; 4) проверить реальные платежи по банковским выпискам; 5) запросить технический паспорт и разрешение на ввод.', 'manual'),
('faq_investment_min',       'Сколько нужно денег для инвестиции в коммерческую недвижимость Краснодара? Вход от 5 млн ₽ — небольшое ПСН или офис 50–80 м² в спальном районе. Качественный объект в ЦМР — от 15–20 млн ₽. ГАБ с арендатором — от 30 млн ₽. Строение целиком — от 50 млн ₽.', 'manual'),
('faq_best_district',        'Какой район Краснодара лучше для инвестиции? Зависит от задачи: ЦМР — максимальные ставки аренды, минимальная вакантность, высокая цена входа. ФМР — хороший баланс цены и доходности, развивающийся район. ЮМР — жилая активность, спрос на услуги (медицина, образование, еда). Прикубанский — низкий порог входа, но и ставки ниже.', 'manual'),
('faq_noi_what',             'Что такое NOI-модель и зачем она нужна? NOI-модель рассчитывает чистый операционный доход объекта, NPV за 10 лет, IRR и срок окупаемости с учётом индексации аренды, вакантности, OPEX и налогов. Позволяет сравнить объекты между собой и с альтернативными инвестициями (депозит, ОФЗ).', 'manual')
INSERT INTO t_p71821556_real_estate_catalog_.vb_test_questions (question, expected_keywords, category) VALUES
